-- Activities: Arabic data + safety guidelines
UPDATE public.activities SET arabic_name='تجربة الغوص', arabic_category='الغوص الحر', arabic_location='جدة، السعودية', arabic_description='اكتشف أعماق البحر الأحمر مع تجربة غوص احترافية لمدة 5 ساعات من جدة. اسبح بين الشعاب المرجانية الملوّنة والكائنات البحرية النابضة بالحياة، برفقة مدرّبين معتمدين وفي مواقع غوص مناسبة لجميع المستويات. مجموعات صغيرة، معدات عالية الجودة، ومياه صافية تجعل من التجربة مغامرة تحت الماء لا تُنسى. رحلتك في البحر الأحمر تبدأ من هنا.', safety_guidelines='Follow the guide''s instructions at all times.', arabic_safety_guidelines='اتبع تعليمات المرشد في جميع الأوقات.' WHERE name='Scuba Diving' AND city='Jeddah';

UPDATE public.activities SET arabic_name='رحلة سفاري في الصحراء', arabic_category='جولات الدفع الرباعي (4×4)', arabic_location='جدة، السعودية', arabic_description='عِش إثارة جولة سفاري بالدراجات الرباعية في الصحراء، وانطلق فوق الكثبان الرملية الذهبية مع الاستمتاع بالمناظر الصحراوية الخلابة. اشعر بالأدرينالين، التقط أجمل المشاهد، وانغمس في جمال وهدوء الصحراء لتجربة مغامرة لا تُنسى.', safety_guidelines='Follow the guide''s instructions at all times. Always wear your seatbelt. Exit the vehicle only when instructed or in an emergency.', arabic_safety_guidelines='اتبع تعليمات المرشد في جميع الأوقات. اربط حزام الأمان دائمًا. لا تخرج من المركبة إلا عند التوجيه أو في حالة طوارئ.' WHERE name='Desert Safari' AND city='Jeddah';

UPDATE public.activities SET arabic_name='رحلة لنصف يوم بالقارب', arabic_category='على الماء', arabic_location='جدة، السعودية', arabic_description='اكتشف ساحل البحر الأحمر وتجربة الحياة البحرية المحلية في جدة. انضم إلى العائلات والسكان المحليين في المرسى، وتفاعل مع المجتمع المحلي، وتعرف على الكنوز البحرية الفريدة من خلال قادة السفن المتحمسين. هذه الجولة مناسبة طوال العام بفضل شتاء جدة المعتدل.' WHERE name='Half day Boat Trip' AND city='Jeddah';

UPDATE public.activities SET arabic_name='جولة خاصة ليوم كامل', arabic_category='جولة سياحية خاصة', arabic_location='جدة، السعودية', arabic_description='اكتشف سحر جدة في جولة خاصة ليوم كامل مع مرشد محلي. تجوّل في الأحياء العصرية، المقاهي، جلسات الشيشة، والمعالم الشهيرة مثل كورنيش البحر الأحمر، المسجد العائم، وأعلى سارية علم. عش تجربة المدينة كما يفعل السكان المحليون واكتشف كنوزها المخفية.' WHERE name='Full day Private Tour' AND city='Jeddah';

UPDATE public.activities SET arabic_name='جولة في الحي التاريخي بجدة مع مرشد محلي', arabic_category='جولة لنصف يوم', arabic_location='جدة، السعودية', arabic_description='اكتشف البلد، الحي التاريخي المسجّل في قائمة التراث العالمي لليونسكو في جدة. تجوّل بين البيوت المبنية من الحجر المرجاني، واستكشف المتاحف والمعارض والكنوز المخفية برفقة مرشد محلي معتمد. عِش التاريخ الغني، والثقافة الحيوية، والجمال الخالد لهذا الحي العريق في جولة لا تُنسى.' WHERE name='Historic Tour' AND city='Jeddah';

UPDATE public.activities SET arabic_name='رحلة تسلق جبل القمر', arabic_category='جولة بالسيارة', arabic_location='جدة، السعودية', arabic_description='تنزه في وادي القمر الساحر واستمتع بالطبيعة السعودية بطريقة فريدة. هذا المسار المميز يوفر هروبًا هادئًا من صخب المدينة، مثالي لمن يبحث عن وقت ممتع في الهواء الطلق.', safety_guidelines='Follow the guide''s instructions at all times. Wear proper hiking shoes and stay on marked trails. Inform the guide immediately in case of any emergency.', arabic_safety_guidelines='اتبع تعليمات المرشد في جميع الأوقات. ارتدِ حذاء مشي مناسبًا والتزم بالمسارات المحددة. أبلغ المرشد فورًا عند أي طارئ.' WHERE name='Moon Mountain Hike' AND city='Jeddah';

UPDATE public.activities SET arabic_name='تجربة ركوب الخيل', arabic_category='جولات على ظهور الحيوانات', arabic_location='جدة، السعودية', arabic_description='استمتع بإثارة مناظر جدة الطبيعية على ظهور الخيل! امتطِ الخيل على طول ساحل شاطئ خليج سلمان الجميل، حيث تلتقي مياه البحر الأحمر الفيروزية بالرمال الناعمة. استمتع بإطلالات البحر، نسيمه العليل، وتجربة هادئة وممتعة على هذا الشاطئ الخلاب.' WHERE name='Horse Riding' AND city='Jeddah';

UPDATE public.activities SET arabic_name='مخيم رويال الفاخر', arabic_category='تخييم', arabic_location='الرياض، السعودية', arabic_description='مخيم صحراوي فسيح يستضيف أكثر من 150 ضيفًا، مثالي للعائلات والفعاليات والمناسبات الخاصة في قلب رمال الرمال الحمراء الهادئة.' WHERE name='Luxury Royal Camp' AND city='Riyadh';

UPDATE public.activities SET arabic_name='سفاري رانغلر', arabic_category='جولة 4×4', arabic_location='الرياض، السعودية', arabic_description='اكتشف جمال الرمال الحمراء في جولة فاخرة بمركبة رانغلر مع مرشدين خبراء يجوبون الكثبان بثقة وراحة.' WHERE name='Wrangler Safari' AND city='Riyadh';

UPDATE public.activities SET arabic_name='ركوب الجمال', arabic_category='جولات على الحيوانات', arabic_location='الرياض، السعودية', arabic_description='جرب ركوب الجمال على الطريقة البدوية بين مناظر صحراوية خلابة وكثبان ذهبية لا تنتهي.' WHERE name='Camel Riding' AND city='Riyadh';

UPDATE public.activities SET arabic_name='ركوب الخيل', arabic_category='جولات على الحيوانات', arabic_location='الرياض، السعودية', arabic_description='استمتع بركوب الخيل عبر الكثبان الحمراء بأسلوب الفروسية العربية الأصيلة.' WHERE name='Horse Riding' AND city='Riyadh';

UPDATE public.activities SET arabic_name='رحلة روحانية', arabic_category='جولات', arabic_location='مكة المكرمة، السعودية', arabic_description='جولة روحانية في مكة تشمل عرفات ومزدلفة ومِنى وجسر الجمرات ومسجد الخيف، ثم جبل النور وغار حراء، وختامًا معرض الوحي.' WHERE name='A Spiritual Journey' AND city='Mecca';

UPDATE public.activities SET arabic_name='متحف برج الساعة', arabic_category='متحف', arabic_location='مكة المكرمة، السعودية', arabic_description='استمتع بإطلالات بانورامية على الحرم من متحف برج الساعة في أبراج البيت، مع رحلة تفاعلية حول الفلك وتطور مكة.' WHERE name='Clock Tower Museum' AND city='Mecca';

UPDATE public.activities SET arabic_name='حياة النبي', arabic_category='جولات', arabic_location='مكة المكرمة، السعودية', arabic_description='رحلة تاريخية وروحانية تتبع خطى النبي محمد ﷺ من جبل ثور ووادي إبراهيم إلى جبل النور.' WHERE name='Life of the Prophet' AND city='Mecca';

UPDATE public.activities SET arabic_name='جولة مصنع الكسوة', arabic_category='جولات', arabic_location='مكة المكرمة، السعودية', arabic_description='تعرّف على تراث الكسوة الشريفة ثم زر موقع الحديبية التاريخي مع مرشدٍ متمكن.' WHERE name='Kiswah Factory Tour' AND city='Mecca';

UPDATE public.activities SET arabic_name='جولة اكتشاف حراء', arabic_category='جولات', arabic_location='مكة المكرمة، السعودية', arabic_description='استكشف حي حراء مع معرض الوحي ومتحف أثر القرآن، ثم تسلّق جبل النور وغار حراء.' WHERE name='Discover Hira Tour' AND city='Mecca';

UPDATE public.activities SET arabic_name='جولة يوم في الحجر', arabic_category='جولات', arabic_location='العلا، السعودية', arabic_description='اخترق تاريخ الأنباط في موقع اليونسكو مع رواة محليين وقصر الفريد ومعالم العلا الأيقونية.' WHERE name='Hegra Day Tour' AND city='AlUla';

UPDATE public.activities SET arabic_name='مراقبة النجوم في الغراميل', arabic_category='الطبيعة والهواء الطلق', arabic_location='العلا، السعودية', arabic_description='أفق درب التبانة وسط تشكيلات صخرية بعيدًا عن التلوث الضوئي، مع عشاء مشوي حول نار.' WHERE name='Gharameel Stargazing' AND city='AlUla';

UPDATE public.activities SET arabic_name='مشي مضمار مداخل', arabic_category='مغامرة', arabic_location='العلا، السعودية', arabic_description='امشِ في مسارات محمية شعبان بين الطبيعة والتكوينات الرملية الخلابة.' WHERE name='Madakhel Garden Hike' AND city='AlUla';

UPDATE public.activities SET arabic_name='مركز ويلز للدراجات', arabic_category='مغامرة', arabic_location='العلا، السعودية', arabic_description='أجر دراجة وانطلق على مسار 26 كم بين العذيب والحجر مع دعم وصيانة وكافيه في النهاية.' WHERE name='Wheels Bike Hub' AND city='AlUla';

UPDATE public.activities SET arabic_name='جولة أثرية', arabic_category='جولة', arabic_location='العلا، السعودية', arabic_description='اكتشف مواقع تنقيب حية مع خبراء وعشاء فاخر في الواحة.' WHERE name='Archaeology Tour' AND city='AlUla';

UPDATE public.activities SET arabic_name='جولة تاريخية', arabic_category='جولات', arabic_location='السودة، السعودية', arabic_description='اكتشف قرية رجال ألمع البالغة من العمر 900 عام قرب أبها في جولة جماعية صغيرة مع توفير وسائل النقل. استمتع بيوم من المشي، مشاهدة المعالم، وتذوق المأكولات المحلية أثناء التعرف على التراث الغني للمملكة العربية السعودية.' WHERE name='Historical Tour' AND city='Southern Provence';

UPDATE public.activities SET arabic_name='رحلة إلى آبار حمى', arabic_category='رحلات', arabic_location='نجران، السعودية', arabic_description='انضم إلى جولة يومية لاستكشاف مدينة الأخدود الأثرية، موقع حِميري قديم يضم آثارًا ونقوشًا، ثم زيارة آبار حِمى، موقع اليونسكو الشهير بمصادر المياه التاريخية والنقوش الصخرية. برفقة خبراء محليين، تقدّم هذه الجولة رحلة أصيلة وذات معنى عبر تاريخ وثقافة جنوب الجزيرة العربية.' WHERE name='Trip to Hima Wells' AND city='Southern Provence';

UPDATE public.activities SET arabic_name='جولة مزرعة القهوة', arabic_category='جولات', arabic_location='أبها، السعودية', arabic_description='اكتشف مزرعة قهوة محلية برفقة المزارعين وتعرف على كيف يشكّل القهوة جزءًا من ثقافة الجنوب. ثم استمتع بمغامرة قيادة عبر الطرق الوعرة في الجبال وصولًا إلى أعلى قمة في الجبل الأسود.' WHERE name='Coffee Plantation Tour' AND city='Southern Provence';

UPDATE public.activities SET arabic_name='مشي سودة', arabic_category='مغامرات', arabic_location='أبها، السعودية', arabic_description='قم برحلة مشي اختيارية بطول 8 كم على ارتفاع 3,000 متر فوق سطح البحر في جبال السودة بأبها. يمتد هذا المسار العريق البالغ عمره 250 عامًا نحو قاعدة الجبل، محاطًا بأشجار العرعر الدائمة الخضرة، رمز المنطقة.' WHERE name='Soudah Hiking' AND city='Southern Provence';

UPDATE public.activities SET arabic_name='متحف فاطمة', arabic_category='متحف', arabic_location='أبها، السعودية', arabic_description='يعرض متحف فاطمة التراث الثقافي الغني للمملكة العربية السعودية من خلال مجموعة مختارة من القطع التقليدية، الملابس، الحرف اليدوية، والمعروضات التاريخية. يمكن للزوار استكشاف تاريخ المملكة وعاداتها وتقاليدها الفنية في بيئة تعليمية تفاعلية تحتفي بالتراث السعودي.' WHERE name='Fatima Museum' AND city='Southern Provence';

