UPDATE public.cars SET arabic_name='شفروليه تاهو', arabic_about='توفر شفروليه تاهو تجربة تنقل مريحة وموثوقة مع مقصورة واسعة وأداء سلس. تُعد خيارًا مناسبًا للعائلات والمجموعات، سواء للتنقل داخل المدينة، رحلات المطار، أو الرحلات الطويلة.', arabic_passenger_line='تتسع لسبعة أشخاص' WHERE name='Chevrolet Tahoe';
UPDATE public.cars SET arabic_name='فورد تورس', arabic_about='تقدم فورد تورس تجربة قيادة مريحة وعملية مع مقصورة واسعة وأداء سلس. تُعد خيارًا مثاليًا للتنقل اليومي داخل المدينة، رحلات المطار، أو الرحلات الجماعية الصغيرة، مع موثوقية وسهولة في الاستخدام.', arabic_passenger_line='تتسع لأربعة أشخاص' WHERE name='Ford Taurus';
UPDATE public.cars SET arabic_name='جي إم سي يوكن', arabic_about='تقدم جي إم سي يوكن تجربة تنقل قوية ومريحة مع مقصورة واسعة وأداء سلس. تُعد خيارًا مثاليًا للعائلات والمجموعات، ومناسبة للتنقل داخل المدينة، الرحلات الطويلة، أو الاستخدام اليومي.', arabic_passenger_line='تتسع لسبعة أشخاص' WHERE name='GMC Yukon';
UPDATE public.cars SET arabic_name='بي إم دبليو 7 سيريز', arabic_about='يقدم بي إم دبليو الفئة السابعة تجربة قيادة فاخرة مع راحة متقنة وتقنيات متقدمة. مقصورة واسعة وفخمة وتصميم أنيق، مثالية لرحلات العمل، المناسبات الخاصة، أو التنقل المميز داخل المدينة.', arabic_passenger_line='تتسع لأربعة أشخاص' WHERE name='BMW 7 Series';
UPDATE public.cars SET arabic_name='مرسيدس بنز الفئة S', arabic_about='تمثل مرسيدس بنز الفئة S رمز الفخامة بامتياز مع راحة استثنائية وتقنية متطورة وتجربة قيادة انسيابية راقية. مثالية لنقل كبار الشخصيات ورحلات الأعمال أو المناسبات الخاصة.', arabic_passenger_line='تتسع لأربعة أشخاص' WHERE name='Mercedes-Benz S-Class';
UPDATE public.cars SET arabic_name='لوسيد إير', arabic_about='يقدّم لوسيد إير تجربة فاخرة عصرية بتصميم أنيق وأداء فائق السلاسة ومقصورة واسعة بتقنيات متقدمة. كهربائي بالكامل وهادئ للغاية، مثالي لمن يبحثون عن الراحة والابتكار والتنقل الراقي داخل المدينة.', arabic_passenger_line='تتسع لأربعة أشخاص' WHERE name='Lucid Air';
UPDATE public.cars SET arabic_name='مرسيدس بنز V-Class', arabic_about='توفر مرسيدس بنز V-Class رحلة واسعة ومريحة، مثالية للعائلات والمجموعات. مع مقصورة فاخرة، مقاعد مرنة، وأداء سلس، فهي الخيار الأمثل للتنقّل داخل المدينة، الجولات، أو النقل الفاخر للمجموعات.', arabic_passenger_line='تتسع لثمانية أشخاص' WHERE name='Mercedes-Benz V-Class';
UPDATE public.cars SET arabic_name='حافلة VIP', arabic_about='توفر حافلة VIP تجربة تنقّل مريحة للمجموعات، مع مقاعد واسعة ومقصورة فاخرة وقيادة سلسة. تُعد خيارًا مثاليًا للعائلات، مجموعات العمل، الفعاليات، والجولات، لتجربة تنقّل راقية ومريحة.', arabic_passenger_line='تتسع لـ 15-20 شخصًا' WHERE name='VIP Mini Bus';
